exam_format.user:
Generate a formal English examination paper as JSON.

Course: {{course}}
Duration: {{durationMinutes}} minutes
Total Marks: {{totalMarks}}

Section Structure:
{{sectionSpec}}

Topics to cover:
{{topics}}

Return ONLY valid JSON matching this structure:
{
  "metadata": {
    "course": "Course Name",
    "institution": "University Name",
    "examType": "Final Examination",
    "durationMinutes": 120,
    "totalMarks": 100
  },
  "instructions": [
    "Answer ALL questions.",
    "Write clearly and legibly.",
    "Show all work for partial credit."
  ],
  "sections": [
    {
      "id": "A",
      "title": "Section A: Multiple Choice",
      "marks": 30,
      "pageBreakBefore": false,
      "questions": [
        {
          "number": 1,
          "marks": 3,
          "type": "mcq",
          "stem": "Question text here?",
          "choices": [
            { "key": "A", "text": "Option A" },
            { "key": "B", "text": "Option B" },
            { "key": "C", "text": "Option C" },
            { "key": "D", "text": "Option D" }
          ]
        }
      ]
    },
    {
      "id": "B",
      "title": "Section B: Short Answer",
      "marks": 30,
      "pageBreakBefore": true,
      "questions": [
        {
          "number": 11,
          "marks": 6,
          "type": "short",
          "prompt": "Explain...",
          "answerLines": 6
        }
      ]
    },
    {
      "id": "C",
      "title": "Section C: Programming",
      "marks": 40,
      "pageBreakBefore": true,
      "questions": [
        {
          "number": 16,
          "marks": 20,
          "type": "programming",
          "prompt": "Write a function...",
          "constraints": ["Do not use..."],
          "codeAreaLines": 18
        }
      ]
    }
  ]
}
